function ModelOneNight:CheckVideoRed()
	if gLGameLanguage:IsUSARegion() then
		--海外屏蔽一千零一夜录像
		return false
	end

	local ref = self:GetModelConfig(ModelOneNight.OneNightVideoRef)
	for k,v in pairs(ref) do
		local isOpen = gModelFunctionOpen:CheckOpenCondition(v.open)
		if isOpen and not self:IsVideoPlayed(k) then
			return true
		end
	end
	return false
end

