function ModelOneNight:IsVideoResCached(resName)
	local filePath = self:GetVideoLocalPath(resName)
	if CS.FileExists(filePath) then
		return true
	end
	return false
end

function ModelOneNight:DownloadVideoRes(itemdata)
	self:StopDownloadVideoRes()
	local remoteData = LRemoteResData:New()
	self._curRemoteData = remoteData

	local endFunc = function()
		GF.CloseWndByName("UIRemoingTip")
		GF.OpenWnd("UIHeartVdo",{itemdata = itemdata})
	end

	local resName = string.format("%s.mp4",itemdata.videoRes)
	remoteData:Create(resName,endFunc)
	local para =
	{
		refId = 260003,
		funcMap =
		{
			[1] = function()
				self:StopDownloadVideoRes()
			end
		},
		callOnClose = function()
			self:StopDownloadVideoRes()
		end,
		key = resName
	}

	GF.OpenWnd("UIRemoingTip",para)
end

function ModelOneNight:StopDownloadVideoRes()
	local remoteData = self._curRemoteData
	if remoteData then
		remoteData:Destroy()
	end

	self._curRemoteData = nil
end

function ModelOneNight:GetVideoLocalPath(resName)
	local filePath = string.format("%sremoteRes/%s.mp4",CS.AppHelper.AppPersistentDataPath,resName)
	return filePath
end

function ModelOneNight:SaveVideoToPhoto(itemdata)
	local filePath = self:GetVideoLocalPath(itemdata.videoRes)
	if not CS.FileExists(filePath) then
		return
	end

	if not self:CheckPhotoPermission() then
		LNativeHelper.RequestPermissionForMedia(ccClientText(19790), ccClientText(19788), ccClientText(19789))
		return
	end

	local desPath = string.format("/game/videos/%s.mp4",itemdata.videoRes)
	CS.SaveVideoToPhoto(filePath,desPath)

end

function ModelOneNight:CheckPhotoPermission()
	if not LNativeHelper.CheckPermissionForMedia() then
		return false
	end

	return true
end

