--观看的红点的记录
function ModelOneNight:AddRecord(refId,type)
	local record = self:GetThemeRecord()
	local data = record[tostring(type)] or {}
	record[tostring(type)] = data
	if data[tostring(refId)] then
		return
	end
	data[tostring(refId)] = 1
	local str = JSON.encode(record)
	LPlayerPrefs.SetThemeRecord(str)

	gModelRedPoint:OnThemeRecordChange(type)
end

--是否重复的记录
function ModelOneNight:IsRecorded(refId,type)
	local record = self:GetThemeRecord()
	local data = record[tostring(type)]
	if not data then
		return
	end
	return data[tostring(refId)]== 1 or false
end

function ModelOneNight:GetThemeRecord()
	if self._themeRecord then
		return self._themeRecord
	end
	local record = {}
	if not string.isempty(LPlayerPrefs.themeRecord) then
		record = JSON.decode(LPlayerPrefs.themeRecord)
	end

	self._themeRecord = record

	return self._themeRecord
end




